'use client';

import * as React from 'react';
import { mockProjects } from '@/lib/mock-data';
import { Button } from '@/components/ui/button';
import {
  Card,
  CardContent,
  CardDescription,
  CardFooter,
  CardHeader,
  CardTitle,
} from '@/components/ui/card';
import { useToast } from '@/hooks/use-toast';
import Link from 'next/link';

export default function AdminRequestsPage() {
  const { toast } = useToast();
  const pendingProjects = mockProjects.filter(
    (p) => p.status === 'En revisión'
  );

  return (
    <div className="space-y-6">
      <h1 className="text-3xl font-bold font-headline">Gestión de Solicitudes</h1>

      <div>
        <h2 className="text-2xl font-semibold mb-4">Sin revisar</h2>
        {pendingProjects.length > 0 ? (
          <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3">
            {pendingProjects.map((project) => (
              <Card key={project.id}>
                <CardHeader>
                  <CardTitle className="truncate hover:underline">
                    {project.title}
                  </CardTitle>
                  <CardDescription>por {project.solicitante.name}</CardDescription>
                </CardHeader>
                <CardContent>
                  <p className="text-sm text-muted-foreground line-clamp-3">
                    {project.abstract}
                  </p>
                </CardContent>
                <CardFooter className="flex justify-end">
                  <Button asChild>
                    <Link href={`/administrador/solicitudes/${project.id}`}>
                      Ver solicitud
                    </Link>
                  </Button>
                </CardFooter>
              </Card>
            ))}
          </div>
        ) : (
          <div className="flex flex-col items-center justify-center text-center p-8 border-2 border-dashed rounded-lg h-64">
            <p className="text-muted-foreground">
              No hay solicitudes de proyectos pendientes de revisión.
            </p>
          </div>
        )}
      </div>
    </div>
  );
}
